function buildWordInfo(answer) {
    if (!answer) return ''
    const words   = answer.split(' ').filter(Boolean)
    const letters = words.reduce((n, w) => n + w.length, 0)
    const wordTxt = words.length === 1 ? '1 kata' : `${words.length} kata`
    return `${wordTxt}  ·  ${letters} huruf`
}

